handler:
return function(res) {
  if (res.error) return ['', res.error.message || '请求失败'];
  try {
    var c = res.choices[0].message.content.trim();
    var m = c.match(/^[A-Z]+$/);
    if (m) return ['', m[0]];
    m = c.match(/[答案是：:]*\s*([A-Z]+)/);
    if (m) return ['', m[1]];
    if (/^(对|是|正确|√|True|T)$/i.test(c)) return ['', '正确'];
    if (/^(错|否|错误|×|False|F)$/i.test(c)) return ['', '错误'];
    return ['', c.split('\n')[0].trim()];
  } catch(e) {
    return ['', '解析失败'];
  }
}
